+//! Token-Batch Firehose Benchmark
+//!
+//! Tests the "Firehose" pattern for MoE expert loading:
+//! - Predict ALL 32 layers upfront for each token
+//! - IO thread races ahead with SSD queue NEVER empty
+//! - 4 staging buffers (768MB) for deep pipelining
+//!
+//! Usage: ./zig-out/bin/bench-double-buffer <model.gguf> [num_tokens]
+//!
+//! Expected: ~3.0 TPS (up from 0.47 TPS with single-layer prefetch)
+
+const std = @import("std");
+const mixtral_lazy = @import("mixtral_lazy.zig");
+const gguf_loader = @import("inference/gguf_loader.zig");
+const moe_metal = @import("moe_metal.zig");
+const objc = @import("inference/metal/objc.zig");
+const TokenBatchLoader = @import("token_batch_loader.zig").TokenBatchLoader;
+
+pub fn main() !void {
+    var gpa = std.heap.GeneralPurposeAllocator(.{}){};
+    defer _ = gpa.deinit();
+    const allocator = gpa.allocator();
+
+    const args = try std.process.argsAlloc(allocator);
+    defer std.process.argsFree(allocator, args);
+
+    if (args.len < 2) {
+        std.debug.print("Usage: {s} <model.gguf> [num_tokens]\n", .{args[0]});
+        std.debug.print("\nBenchmarks token-batch firehose loading for Mixtral 8x7B.\n", .{});
+        std.debug.print("Target: 3.0 TPS (6x improvement over single-layer prefetch 0.47 TPS)\n", .{});
+        return;
+    }
+
+    const model_path = args[1];
+    const total_tokens: u32 = if (args.len > 2) std.fmt.parseInt(u32, args[2], 10) catch 20 else 20;
+    const warmup_tokens: u32 = if (total_tokens > 5) 5 else 0;
+    const measure_tokens: u32 = total_tokens - warmup_tokens;
+
+    std.debug.print("\n", .{});
+    std.debug.print("╔══════════════════════════════════════════════════════════════╗\n", .{});
+    std.debug.print("║      TOKEN-BATCH FIREHOSE BENCHMARK                          ║\n", .{});
+    std.debug.print("║      SSD Queue Never Empty - All 32 Layers Predicted         ║\n", .{});
+    std.debug.print("╚══════════════════════════════════════════════════════════════╝\n", .{});
+    std.debug.print("\n", .{});
+    std.debug.print("Model: {s}\n", .{model_path});
+    std.debug.print("Total tokens: {} (warmup: {}, measured: {})\n", .{ total_tokens, warmup_tokens, measure_tokens });
+    std.debug.print("\n", .{});
+
+    // Initialize engine
+    std.debug.print("Initializing engine...\n", .{});
+    const init_start = std.time.nanoTimestamp();
+
+    // Load model
+    var loader = try gguf_loader.GGUFLoader.init(allocator, model_path);
+    defer loader.deinit();
+
+    var moe_engine = try moe_metal.MetalMoEEngine.init(allocator);
+    defer moe_engine.deinit();
+
+    var engine = try mixtral_lazy.MixtralLazyEngine.init(allocator, &loader, moe_engine);
+    defer engine.deinit();
+
+    // Load embeddings
+    try engine.ensureEmbeddingsLoaded();
+
+    // Initialize token-batch loader (firehose mode)
+    std.debug.print("Initializing token-batch loader (4 × 192MB = 768MB staging pools)...\n", .{});
+    try moe_engine.initTokenBatchLoader(model_path, loader.tensor_data_offset);
+    moe_engine.startTokenBatchIO();
+
+    const init_end = std.time.nanoTimestamp();
+    const init_ms = @as(f64, @floatFromInt(init_end - init_start)) / 1_000_000.0;
+    std.debug.print("Initialization complete: {d:.1} ms\n\n", .{init_ms});
+
+    // Prompt: "The capital of France is"
+    const prompt_tokens = [_]u32{ 1, 415, 5565, 302, 4843, 349 };
+
+    std.debug.print("═══════════════════════════════════════════════════════════════\n", .{});
+    std.debug.print("                      BENCHMARK START                          \n", .{});
+    std.debug.print("═══════════════════════════════════════════════════════════════\n\n", .{});
+
+    // Process prompt (prefill) - first pass builds expert history
+    std.debug.print("Prefill ({} tokens)...\n", .{prompt_tokens.len});
+    const prefill_start = std.time.nanoTimestamp();
+
+    var logits: []const f32 = undefined;
+    for (prompt_tokens, 0..) |tok, i| {
+        // Use forwardTokenBatch - first pass is sync, but builds expert history
+        logits = try engine.forwardTokenBatch(tok, @intCast(i));
+    }
+
+    const prefill_end = std.time.nanoTimestamp();
+    const prefill_ms = @as(f64, @floatFromInt(prefill_end - prefill_start)) / 1_000_000.0;
+    const prefill_tps = @as(f64, @floatFromInt(prompt_tokens.len)) / (prefill_ms / 1000.0);
+    std.debug.print("Prefill: {d:.1} ms ({d:.2} tokens/sec)\n\n", .{ prefill_ms, prefill_tps });
+
+    // Generation loop
+    var pos: u32 = @intCast(prompt_tokens.len);
+    var last_token: u32 = prompt_tokens[prompt_tokens.len - 1];
+
+    // Arrays to store per-token timing
+    var token_times = try allocator.alloc(i64, total_tokens);
+    defer allocator.free(token_times);
+
+    var generated_tokens = try allocator.alloc(u32, total_tokens);
+    defer allocator.free(generated_tokens);
+
+    std.debug.print("Generating {} tokens with firehose pattern (all 32 layers predicted)...\n", .{total_tokens});
+
+    const gen_start = std.time.nanoTimestamp();
+    var warmup_end: i128 = 0;
+
+    for (0..total_tokens) |i| {
+        const token_start = std.time.nanoTimestamp();
+
+        // Forward pass with token-batch prediction (firehose - SSD queue never empty)
+        logits = try engine.forwardTokenBatch(last_token, pos);
+
+        // Greedy sampling (argmax)
+        var max_idx: u32 = 0;
+        var max_val: f32 = logits[0];
+        for (1..engine.config.n_vocab) |j| {
+            if (logits[j] > max_val) {
+                max_val = logits[j];
+                max_idx = @intCast(j);
+            }
+        }
+
+        const token_end = std.time.nanoTimestamp();
+        token_times[i] = @intCast(token_end - token_start);
+        generated_tokens[i] = max_idx;
+
+        // Update for next iteration
+        last_token = max_idx;
+        pos += 1;
+
+        // Mark end of warmup
+        if (i == warmup_tokens - 1) {
+            warmup_end = token_end;
+        }
+
+        // Progress indicator every 5 tokens
+        if ((i + 1) % 5 == 0) {
+            const elapsed_ms = @as(f64, @floatFromInt(token_end - gen_start)) / 1_000_000.0;
+            const current_tps = @as(f64, @floatFromInt(i + 1)) / (elapsed_ms / 1000.0);
+            std.debug.print("  Token {}/{}: {d:.2} TPS (current)\n", .{ i + 1, total_tokens, current_tps });
+        }
+
+        // Stop on EOS
+        if (max_idx == 2) {
+            std.debug.print("  EOS token generated at position {}\n", .{i});
+            break;
+        }
+    }
+
+    const gen_end = std.time.nanoTimestamp();
+
+    // Calculate metrics
+    const total_gen_ns: i64 = @intCast(gen_end - gen_start);
+    const warmup_ns: i64 = @intCast(warmup_end - gen_start);
+    const measured_ns: i64 = @intCast(gen_end - warmup_end);
+
+    const total_gen_ms = @as(f64, @floatFromInt(total_gen_ns)) / 1_000_000.0;
+    const warmup_ms = @as(f64, @floatFromInt(warmup_ns)) / 1_000_000.0;
+    const measured_ms = @as(f64, @floatFromInt(measured_ns)) / 1_000_000.0;
+
+    const total_tps = @as(f64, @floatFromInt(total_tokens)) / (total_gen_ms / 1000.0);
+    const measured_tps = @as(f64, @floatFromInt(measure_tokens)) / (measured_ms / 1000.0);
+
+    // Per-token statistics (excluding warmup)
+    var min_time: i64 = std.math.maxInt(i64);
+    var max_time: i64 = 0;
+    var sum_time: i64 = 0;
+
+    for (warmup_tokens..total_tokens) |i| {
+        const t = token_times[i];
+        sum_time += t;
+        if (t < min_time) min_time = t;
+        if (t > max_time) max_time = t;
+    }
+
+    const avg_time_ms = @as(f64, @floatFromInt(sum_time)) / @as(f64, @floatFromInt(measure_tokens)) / 1_000_000.0;
+    const min_time_ms = @as(f64, @floatFromInt(min_time)) / 1_000_000.0;
+    const max_time_ms = @as(f64, @floatFromInt(max_time)) / 1_000_000.0;
+
+    std.debug.print("\n", .{});
+    std.debug.print("═══════════════════════════════════════════════════════════════\n", .{});
+    std.debug.print("                      BENCHMARK RESULTS                        \n", .{});
+    std.debug.print("═══════════════════════════════════════════════════════════════\n\n", .{});
+
+    std.debug.print("THROUGHPUT:\n", .{});
+    std.debug.print("  Total generation:     {d:.2} tokens/sec\n", .{total_tps});
+    std.debug.print("  Measured (no warmup): {d:.2} tokens/sec\n", .{measured_tps});
+    std.debug.print("\n", .{});
+
+    std.debug.print("LATENCY (per token, measured phase):\n", .{});
+    std.debug.print("  Average: {d:.1} ms\n", .{avg_time_ms});
+    std.debug.print("  Min:     {d:.1} ms\n", .{min_time_ms});
+    std.debug.print("  Max:     {d:.1} ms\n", .{max_time_ms});
+    std.debug.print("\n", .{});
+
+    std.debug.print("TIMING BREAKDOWN:\n", .{});
+    std.debug.print("  Prefill:     {d:.1} ms ({} tokens)\n", .{ prefill_ms, prompt_tokens.len });
+    std.debug.print("  Warmup:      {d:.1} ms ({} tokens)\n", .{ warmup_ms, warmup_tokens });
+    std.debug.print("  Measured:    {d:.1} ms ({} tokens)\n", .{ measured_ms, measure_tokens });
+    std.debug.print("  Total gen:   {d:.1} ms ({} tokens)\n", .{ total_gen_ms, total_tokens });
+    std.debug.print("\n", .{});
+
+    // Performance assessment
+    std.debug.print("ASSESSMENT:\n", .{});
+    if (measured_tps >= 3.0) {
+        std.debug.print("  ✓ TARGET MET: {d:.1} TPS >= 3.0 TPS target\n", .{measured_tps});
+        std.debug.print("    Firehose pattern is working! SSD queue never empty.\n", .{});
+    } else if (measured_tps >= 1.0) {
+        std.debug.print("  ⚠ PARTIAL: {d:.1} TPS - good improvement but below 3.0 target\n", .{measured_tps});
+    } else if (measured_tps >= 0.1) {
