+//! Speculative Decoding Benchmark for Mixtral 8x7B
+//!
+//! Compares speculative decoding vs baseline (non-speculative) performance.
+//!
+//! Usage:
+//!   ./zig-out/bin/bench-speculative <target.gguf> <draft.gguf> [--tokens N] [--depth K]
+//!
+//! Expected results on 16GB Mac:
+//!   Baseline: ~0.05 TPS (20 seconds/token)
+//!   Speculative (depth=5): ~0.15-0.25 TPS (4-7 seconds/token)
+
+const std = @import("std");
+const speculative_lazy = @import("speculative_lazy.zig");
+const mixtral_lazy = @import("mixtral_lazy.zig");
+const gguf_loader = @import("inference/gguf_loader.zig");
+const moe_metal = @import("moe_metal.zig");
+const llama = @import("llama.zig");
+const c = llama.c;
+
+pub fn main() !void {
+    var gpa = std.heap.GeneralPurposeAllocator(.{}){};
+    defer _ = gpa.deinit();
+    const allocator = gpa.allocator();
+
+    const args = try std.process.argsAlloc(allocator);
+    defer std.process.argsFree(allocator, args);
+
+    if (args.len < 3) {
+        std.debug.print(
+            \\Usage: {s} <target.gguf> <draft.gguf> [options]
+            \\
+            \\Options:
+            \\  --tokens N   Number of tokens to generate (default: 20)
+            \\  --depth K    Speculation depth (default: 5)
+            \\  --baseline   Also run baseline (non-speculative) for comparison
+            \\
+            \\Example:
+            \\  {s} ~/.zell/models/blobs/Mixtral-8x7B-Instruct-v0.1-Q4_K_M.gguf \
+            \\      ~/.zell/models/blobs/tinyllama-1.1b-chat-v1.0.Q4_K_M.gguf \
+            \\      --tokens 20 --depth 5
+            \\
+        , .{ args[0], args[0] });
+        return;
+    }
+
+    const target_path = args[1];
+    const draft_path = args[2];
+
+    // Parse options
+    var num_tokens: u32 = 20;
+    var depth: u32 = 5;
+    var run_baseline = false;
+
+    var i: usize = 3;
+    while (i < args.len) : (i += 1) {
+        if (std.mem.eql(u8, args[i], "--tokens") and i + 1 < args.len) {
+            num_tokens = std.fmt.parseInt(u32, args[i + 1], 10) catch 20;
+            i += 1;
+        } else if (std.mem.eql(u8, args[i], "--depth") and i + 1 < args.len) {
+            depth = std.fmt.parseInt(u32, args[i + 1], 10) catch 5;
+            i += 1;
+        } else if (std.mem.eql(u8, args[i], "--baseline")) {
+            run_baseline = true;
+        }
+    }
+
+    // Print header
+    std.debug.print("\n", .{});
+    std.debug.print("╔══════════════════════════════════════════════════════════════╗\n", .{});
+    std.debug.print("║       SPECULATIVE DECODING BENCHMARK (Strategy 2)            ║\n", .{});
+    std.debug.print("╚══════════════════════════════════════════════════════════════╝\n", .{});
+    std.debug.print("\n", .{});
+    std.debug.print("Target: {s}\n", .{std.fs.path.basename(target_path)});
+    std.debug.print("Draft:  {s}\n", .{std.fs.path.basename(draft_path)});
+    std.debug.print("Tokens: {}, Depth: {}\n", .{ num_tokens, depth });
+    std.debug.print("\n", .{});
+
+    // Test prompt
+    const prompt = "The capital of France is";
+
+    // Tokenize prompt using draft model (they share tokenizer)
+    std.debug.print("Loading draft model for tokenization...\n", .{});
+    var draft_model = try llama.Model.load(draft_path, .{
+        .n_gpu_layers = 0,
+        .use_mmap = true,
+        .vocab_only = true, // Only load vocab for tokenization
+    });
+    defer draft_model.deinit();
+
+    const vocab = draft_model.getVocab();
+    var prompt_tokens: [256]c.llama_token = undefined;
+    const n_prompt = c.llama_tokenize(
+        vocab,
+        prompt.ptr,
+        @intCast(prompt.len),
+        &prompt_tokens,
+        @intCast(prompt_tokens.len),
+        true,
+        true,
+    );
+
+    if (n_prompt < 0) {
+        std.debug.print("Error: Failed to tokenize prompt\n", .{});
+        return;
+    }
+
+    const n_prompt_tokens: usize = @intCast(n_prompt);
+    std.debug.print("Prompt: \"{s}\" ({} tokens)\n", .{ prompt, n_prompt_tokens });
+
+    // Convert to u32 array
+    var prompt_u32: [256]u32 = undefined;
+    for (0..n_prompt_tokens) |j| {
+        prompt_u32[j] = @intCast(prompt_tokens[j]);
+    }
+
+    // Unload vocab-only model
+    draft_model.deinit();
+
+    // Run baseline if requested
+    if (run_baseline) {
+        std.debug.print("\n", .{});
+        std.debug.print("═══════════════════════════════════════════════════════════════\n", .{});
+        std.debug.print("                      BASELINE (no speculation)                \n", .{});
+        std.debug.print("═══════════════════════════════════════════════════════════════\n", .{});
+
+        var loader = try gguf_loader.GGUFLoader.init(allocator, target_path);
+        defer loader.deinit();
+
+        var moe = try moe_metal.MetalMoEEngine.init(allocator);
+        defer moe.deinit();
+
+        var engine = try mixtral_lazy.MixtralLazyEngine.init(allocator, &loader, moe);
+        defer engine.deinit();
+
+        const baseline_start = std.time.nanoTimestamp();
+
+        // Process prompt
+        for (0..n_prompt_tokens) |j| {
+            _ = try engine.forwardTrueSingleSubmit(prompt_u32[j], @intCast(j));
+        }
+
+        // Generate tokens
+        var pos: u32 = @intCast(n_prompt_tokens);
+        var last_token: u32 = prompt_u32[n_prompt_tokens - 1];
+        var baseline_generated: u32 = 0;
+
+        std.debug.print("\nGenerating {} tokens (baseline)...\n", .{num_tokens});
+        std.debug.print("Output: ", .{});
+
+        while (baseline_generated < num_tokens) {
+            const logits = try engine.forwardTrueSingleSubmit(last_token, pos);
+            const token = engine.sampleGreedy(logits);
+
+            // Output token
+            var buf: [256]u8 = undefined;
+            // Need to reload vocab for output
+            const token_str = std.fmt.bufPrint(&buf, "[{d}]", .{token}) catch "[?]";
+            std.debug.print("{s}", .{token_str});
+
+            if (token == 2) break; // EOS
+            last_token = token;
+            pos += 1;
+            baseline_generated += 1;
+        }
+
+        const baseline_end = std.time.nanoTimestamp();
+        const baseline_time_ms = @as(f64, @floatFromInt(baseline_end - baseline_start)) / 1_000_000.0;
+        const baseline_tps = @as(f64, @floatFromInt(baseline_generated)) * 1000.0 / baseline_time_ms;
+
+        std.debug.print("\n\n", .{});
+        std.debug.print("Baseline: {} tokens in {d:.1}ms = {d:.3} TPS\n", .{
+            baseline_generated,
+            baseline_time_ms,
+            baseline_tps,
+        });
+    }
+
+    // Run speculative decoding
+    std.debug.print("\n", .{});
+    std.debug.print("═══════════════════════════════════════════════════════════════\n", .{});
+    std.debug.print("                  SPECULATIVE DECODING (depth={})              \n", .{depth});
+    std.debug.print("═══════════════════════════════════════════════════════════════\n", .{});
+
+    var spec_engine = try speculative_lazy.SpeculativeLazyEngine.init(
+        allocator,
+        draft_path,
+        target_path,
+    );
+    defer spec_engine.deinit();
+
+    const spec_start = std.time.nanoTimestamp();
+
+    std.debug.print("\nOutput: ", .{});
+
+    try spec_engine.generate(
+        prompt_u32[0..n_prompt_tokens],
+        .{
+            .speculation_depth = depth,
+            .max_tokens = num_tokens,
+            .adaptive_depth = true,
+        },
+    );
+
+    const spec_end = std.time.nanoTimestamp();
+    const spec_time_ms = @as(f64, @floatFromInt(spec_end - spec_start)) / 1_000_000.0;
+    const spec_tps = @as(f64, @floatFromInt(spec_engine.total_tokens)) * 1000.0 / spec_time_ms;
+
+    std.debug.print("\n", .{});
+    std.debug.print("Speculative: {} tokens in {d:.1}ms = {d:.3} TPS\n", .{
+        spec_engine.total_tokens,
+        spec_time_ms,
+        spec_tps,
+    });
+
+    // Final summary
+    std.debug.print("\n", .{});
+    std.debug.print("═══════════════════════════════════════════════════════════════\n", .{});
+    std.debug.print("                         SUMMARY                               \n", .{});
+    std.debug.print("═══════════════════════════════════════════════════════════════\n", .{});
+    std.debug.print("Speculation depth:     {}\n", .{depth});
+    std.debug.print("Tokens generated:      {}\n", .{spec_engine.total_tokens});
+    std.debug.print("Time:                  {d:.1} ms\n", .{spec_time_ms});
+    std.debug.print("Throughput:            {d:.3} TPS\n", .{spec_tps});
+    std.debug.print("Time per token:        {d:.1} s\n", .{spec_time_ms / 1000.0 / @as(f64, @floatFromInt(@max(spec_engine.total_tokens, 1)))});
+    std.debug.print("═══════════════════════════════════════════════════════════════\n", .{});
+}

