+//! Double-Buffer Async Loader for MoE Expert Weights
+//!
+//! Implements Token-Level Speculation to break the Memory Wall.
+//!
+//! Key Insight:
+//!   - Expert compute: ~0.05ms (GPU is fast)
+//!   - Expert load: ~40ms (SSD is slow)
+//!   - Solution: Load Layer L+1 while computing Layer L
+//!
+//! Speculation Strategy (Last Token Heuristic):
+//!   - Assume Token N+1 uses same experts as Token N at each layer
+//!   - Hit rate: 40-60% (temporal locality)
+//!   - On hit: Zero latency (experts pre-loaded)
+//!   - On miss: Fall back to synchronous load
+//!
+//! Architecture:
+//!   Pool A: GPU currently computing
+//!   Pool B: IO thread loading next layer (speculative)
+//!   Swap at layer boundary
+//!
+//! Expected: ~3.0 TPS (up from 0.02 TPS synchronous)
+
+const std = @import("std");
+const objc = @import("inference/metal/objc.zig");
+
+const c = @cImport({
+    @cInclude("fcntl.h");
+    @cInclude("unistd.h");
+});
+
+pub const DoubleBufferLoader = struct {
+    const Self = @This();
+
+    /// Result type for speculation validation (must be named to allow cross-file usage)
+    pub const SpeculationResult = struct {
+        buffer: objc.MTLBuffer,
+        gate_offsets: [2]usize,
+        up_offsets: [2]usize,
+        down_offsets: [2]usize,
+        expert_count: usize,
+    };
+
+    /// Stats type for double-buffer performance tracking
+    pub const Stats = struct {
+        hits: u64,
+        misses: u64,
+        hit_rate: f64,
+        bytes_loaded_mb: u64,
+    };
+
+    /// Maximum experts per layer (Mixtral uses top-2)
+    pub const MAX_EXPERTS: usize = 2;
+    /// Tensors per expert: gate, up, down
+    pub const TENSORS_PER_EXPERT: usize = 3;
+    /// Total slots per pool
+    pub const SLOTS_PER_POOL: usize = MAX_EXPERTS * TENSORS_PER_EXPERT; // 6
+
+    /// Size of each tensor slot (~27MB for Mixtral Q4_K expert weights)
+    pub const SLOT_SIZE: usize = 32 * 1024 * 1024; // 32MB to be safe
+
+    /// Pool size = 6 slots × 32MB = 192MB per pool
+    pub const POOL_SIZE: usize = SLOTS_PER_POOL * SLOT_SIZE;
+
+    /// Expert tensor info for loading
