+        var total_speculated: u64 = 0;
+        var total_rounds: u64 = 0;
+
+        // Process prompt with FULL model (we need valid KV cache at all 32 layers for verification)
+        // Using draft layers for prefill would leave layers 15-31 with stale/empty KV cache
