+
+        log.info("Layer-split stats: {} rounds, {}/{} accepted ({d:.1}%)", .{
+            total_rounds,
+            total_accepted,
+            total_speculated,
+            acceptance_rate,
+        });
+
+        return try tokens.toOwnedSlice(self.allocator);
+    }
