+//! Speculative Decoding for MixtralLazyEngine
+//!
+//! Implements speculative decoding to break the memory wall:
+//! - Draft model: Small model (TinyLlama Q4, ~700MB) runs on GPU via llama.cpp
+//! - Target model: Mixtral 8x7B runs on our MixtralLazyEngine with ExpertCache
+//!
+//! The key insight: We pay 20 seconds of SSD I/O per forward pass.
+//! With speculation, we generate K tokens with the draft model (fast),
+//! then verify all K in one Mixtral pass (slow but amortized).
+//!
+//! Expected speedup: 3-5x (from 0.05 TPS to 0.15-0.25 TPS)
+
+const std = @import("std");
+const llama = @import("llama.zig");
+const mixtral_lazy = @import("mixtral_lazy.zig");
+const gguf_loader = @import("inference/gguf_loader.zig");
+const moe_metal = @import("moe_metal.zig");
+const c = llama.c;
+
+const log = std.log.scoped(.speculative);
+
+/// Speculative decoding configuration
+pub const SpeculativeConfig = struct {
+    /// Number of tokens to speculate (K)
+    speculation_depth: u32 = 5,
+    /// Minimum speculation depth
+    min_depth: u32 = 2,
+    /// Maximum speculation depth
+    max_depth: u32 = 12,
+    /// Enable adaptive depth based on acceptance rate
+    adaptive_depth: bool = true,
+    /// Maximum tokens to generate
+    max_tokens: u32 = 100,
+    /// Temperature for draft model (0 = greedy)
+    draft_temperature: f32 = 0.0,
+};
+
+/// Speculative Decoding Engine using MixtralLazyEngine as target
+pub const SpeculativeLazyEngine = struct {
+    allocator: std.mem.Allocator,
+
+    // Draft model - small, fast, GPU-resident (llama.cpp)
+    draft_model: llama.Model,
+    draft_ctx: llama.Context,
+    draft_sampler: *c.llama_sampler,
+
+    // Target model - our MixtralLazyEngine with ExpertCache
+    target: *mixtral_lazy.MixtralLazyEngine,
+    target_loader: gguf_loader.GGUFLoader,  // Stored by value
+    target_moe: *moe_metal.MetalMoEEngine,  // Already a pointer from init
+
+    // Statistics
+    total_tokens: u64 = 0,
+    accepted_tokens: u64 = 0,
+    speculation_rounds: u64 = 0,
+    draft_tokens_generated: u64 = 0,
+
+    const Self = @This();
+
+    /// Initialize speculative decoding engine
+    pub fn init(
+        allocator: std.mem.Allocator,
+        draft_model_path: []const u8,
+        target_model_path: []const u8,
+    ) !*Self {
+        log.info("Initializing Speculative Decoding Engine", .{});
+        log.info("  Draft model: {s}", .{std.fs.path.basename(draft_model_path)});
+        log.info("  Target model: {s}", .{std.fs.path.basename(target_model_path)});
+
+        const self = try allocator.create(Self);
+        errdefer allocator.destroy(self);
+
+        // Initialize draft model (llama.cpp, CPU for now - Metal shader compilation issue)
+        // TinyLlama 1.1B runs fast enough on CPU (~50 tok/s) for draft generation
+        log.info("Loading draft model (CPU)...", .{});
+        self.draft_model = try llama.Model.load(draft_model_path, .{
+            .n_gpu_layers = 0, // CPU-only to avoid Metal shader compilation issues
+            .use_mmap = true,
+            .use_mlock = false,
+        });
+        errdefer self.draft_model.deinit();
+
+        self.draft_ctx = try llama.Context.init(&self.draft_model, .{
+            .n_ctx = 4096,
+            .n_batch = 512,
+        });
+        errdefer self.draft_ctx.deinit();
+
+        // Initialize draft sampler (greedy)
+        self.draft_sampler = c.llama_sampler_chain_init(c.llama_sampler_chain_default_params()) orelse
+            return error.SamplerInitFailed;
+        c.llama_sampler_chain_add(self.draft_sampler, c.llama_sampler_init_greedy());
+
+        // Initialize target model (MixtralLazyEngine)
+        log.info("Loading target model (Mixtral + ExpertCache)...", .{});
+
+        self.target_loader = try gguf_loader.GGUFLoader.init(allocator, target_model_path);
+        errdefer self.target_loader.deinit();
+
+        self.target_moe = try moe_metal.MetalMoEEngine.init(allocator);
+        errdefer self.target_moe.deinit();
+
+        self.target = try mixtral_lazy.MixtralLazyEngine.init(
+            allocator,
+            &self.target_loader,  // Pass pointer to our stored loader
+            self.target_moe,      // Already a pointer
+        );
+        errdefer self.target.deinit();
+
+        self.allocator = allocator;
+        self.total_tokens = 0;
+        self.accepted_tokens = 0;
+        self.speculation_rounds = 0;
+        self.draft_tokens_generated = 0;
+
+        log.info("Speculative engine ready!", .{});
+
+        return self;
+    }
+
+    pub fn deinit(self: *Self) void {
+        c.llama_sampler_free(self.draft_sampler);
+        self.draft_ctx.deinit();
+        self.draft_model.deinit();
+        self.target.deinit();
+        self.target_moe.deinit();
+        self.target_loader.deinit();
+        self.allocator.destroy(self);
+    }
+
+    /// Generate tokens using speculative decoding
+    pub fn generate(
+        self: *Self,
+        prompt_tokens: []const u32,
+        config: SpeculativeConfig,
+    ) !void {
+        const vocab = self.draft_model.getVocab();
+
+        // Process prompt through draft model
+        log.info("Processing prompt ({} tokens) through draft model...", .{prompt_tokens.len});
+        try self.processDraftPrompt(prompt_tokens);
+
+        // Process prompt through target model
+        log.info("Processing prompt through target model...", .{});
+        for (prompt_tokens, 0..) |tok, i| {
+            _ = try self.target.forwardTrueSingleSubmit(tok, @intCast(i));
+        }
+
+        var pos: u32 = @intCast(prompt_tokens.len);
+        var n_generated: u32 = 0;
+        var current_depth: u32 = config.speculation_depth;
+
+        // Adaptive depth tracking
+        var recent_accepted: u32 = 0;
+        var recent_total: u32 = 0;
+        const adapt_window: u32 = 3;
+
+        log.info("Starting speculative generation (depth={})...", .{current_depth});
+        std.debug.print("\n", .{});
+
+        // Feed last prompt token to draft for first speculation
+        var last_token: u32 = prompt_tokens[prompt_tokens.len - 1];
+
+        while (n_generated < config.max_tokens) {
+            self.speculation_rounds += 1;
+
+            // Step 1: Draft generates K candidate tokens
+            var draft_tokens: [16]u32 = undefined;
+            const k = @min(current_depth, 16);
+            var draft_count: usize = 0;
+
+            for (0..k) |_| {
+                // Sample from draft
+                const token = @as(u32, @intCast(c.llama_sampler_sample(self.draft_sampler, self.draft_ctx.handle, -1)));
+
+                // Check EOS
+                if (c.llama_vocab_is_eog(vocab, @intCast(token))) {
+                    break;
+                }
+
+                draft_tokens[draft_count] = token;
+                draft_count += 1;
+                self.draft_tokens_generated += 1;
+
+                // Feed token back to draft for next sample
+                try self.feedDraftToken(token, pos + @as(u32, @intCast(draft_count)) - 1);
+            }
+
+            if (draft_count == 0) {
+                // Draft produced EOS
+                break;
+            }
+
+            // Debug: show draft tokens
+            log.info("Draft proposed {} tokens: {any}", .{ draft_count, draft_tokens[0..draft_count] });
+
+            // Step 2: Target verifies all K tokens
+            const result = try self.target.verifyDraftTokens(
+                draft_tokens[0..draft_count],
+                pos,
+            );
+
+            // Debug: show verification result
+            if (result.correct_token) |correct| {
+                log.info("Target says correct token should be: {} (accepted {} of {})", .{ correct, result.accepted, draft_count });
+            } else {
+                log.info("All {} draft tokens accepted!", .{draft_count});
+            }
+
+            // Step 3: Output accepted tokens
+            for (0..result.accepted) |i| {
+                const tok = draft_tokens[i];
+                self.outputToken(tok, vocab);
+                self.accepted_tokens += 1;
+                self.total_tokens += 1;
+                last_token = tok;
+            }
+
+            // Step 4: Handle mismatch
+            if (result.correct_token) |correct_tok| {
+                // Output target's correct token
+                self.outputToken(correct_tok, vocab);
+                self.total_tokens += 1;
+                last_token = correct_tok;
+
+                // Rollback draft KV cache to accepted position
+                const rollback_pos = pos + @as(u32, @intCast(result.accepted));
+                self.rollbackDraftKV(rollback_pos);
+                // Feed the correct token to draft
+                try self.feedDraftToken(correct_tok, rollback_pos);
+
+                // Also rollback target if needed
+                if (result.accepted < draft_count) {
+                    self.target.clearKVCacheFrom(rollback_pos + 1);
+                }
+            }
+
+            // Update position
+            const tokens_this_round = result.accepted + @as(usize, if (result.correct_token != null) 1 else 0);
+            pos += @intCast(tokens_this_round);
+            n_generated += @intCast(tokens_this_round);
+
+            // Track for adaptive depth
+            recent_accepted += @intCast(result.accepted);
+            recent_total += @intCast(draft_count);
+
+            // Adaptive depth adjustment
+            if (config.adaptive_depth and self.speculation_rounds % adapt_window == 0 and recent_total > 0) {
+                const rate = @as(f32, @floatFromInt(recent_accepted)) / @as(f32, @floatFromInt(recent_total));
+
+                if (rate > 0.7 and current_depth < config.max_depth) {
+                    current_depth = @min(current_depth + 1, config.max_depth);
+                } else if (rate < 0.3 and current_depth > config.min_depth) {
+                    current_depth = @max(current_depth -| 1, config.min_depth);
+                }
+
+                recent_accepted = 0;
+                recent_total = 0;
+            }
+
+            // Check EOS
+            if (result.correct_token) |tok| {
+                if (c.llama_vocab_is_eog(vocab, @intCast(tok))) break;
+            } else if (result.accepted > 0) {
+                const last_accepted = draft_tokens[result.accepted - 1];
+                if (c.llama_vocab_is_eog(vocab, @intCast(last_accepted))) break;
+            }
+
+            // If all accepted, sample bonus token from target
+            if (result.correct_token == null and result.accepted == draft_count) {
+                // Get logits from last position and sample
+                const logits = try self.target.forwardTrueSingleSubmit(last_token, pos - 1);
+                const bonus_tok = self.target.sampleGreedy(logits);
+
+                if (!c.llama_vocab_is_eog(vocab, @intCast(bonus_tok))) {
+                    self.outputToken(bonus_tok, vocab);
+                    self.total_tokens += 1;
+                    self.accepted_tokens += 1;
+                    last_token = bonus_tok;
+                    try self.feedDraftToken(bonus_tok, pos);
+                    pos += 1;
+                    n_generated += 1;
+                }
+            }
+        }
+
+        std.debug.print("\n\n", .{});
+        self.printStats();
+    }
+
+    /// Process prompt through draft model
+    fn processDraftPrompt(self: *Self, tokens: []const u32) !void {
+        const n = tokens.len;
+        var batch = c.llama_batch_init(@intCast(n), 0, 1);
+        defer c.llama_batch_free(batch);
+
+        for (0..n) |i| {
+            batch.token[i] = @intCast(tokens[i]);
+            batch.pos[i] = @intCast(i);
+            batch.n_seq_id[i] = 1;
+            batch.seq_id[i][0] = 0;
+            batch.logits[i] = 0;
+        }
+        batch.logits[n - 1] = 1;
+        batch.n_tokens = @intCast(n);
+
+        if (c.llama_decode(self.draft_ctx.handle, batch) != 0) {
+            return error.DraftDecodeFailed;
+        }
+    }
+
+    /// Feed a single token to draft model
+    fn feedDraftToken(self: *Self, token: u32, pos: u32) !void {
+        var batch = c.llama_batch_init(1, 0, 1);
+        defer c.llama_batch_free(batch);
+
+        batch.token[0] = @intCast(token);
+        batch.pos[0] = @intCast(pos);
+        batch.n_seq_id[0] = 1;
+        batch.seq_id[0][0] = 0;
+        batch.logits[0] = 1;
+        batch.n_tokens = 1;
+
+        if (c.llama_decode(self.draft_ctx.handle, batch) != 0) {
+            return error.DraftDecodeFailed;
+        }
+    }
+
+    /// Rollback draft KV cache to a position
+    fn rollbackDraftKV(self: *Self, from_pos: u32) void {
+        const mem = c.llama_get_memory(self.draft_ctx.handle);
+        _ = c.llama_memory_seq_rm(mem, 0, @intCast(from_pos), -1);
+    }
+
+    /// Output a token to stderr (for debugging)
+    fn outputToken(_: *Self, token: u32, vocab: *const c.llama_vocab) void {
+        var buf: [256]u8 = undefined;
+        const len = c.llama_token_to_piece(
+            vocab,
+            @intCast(token),
+            &buf,
+            @intCast(buf.len),
+            0,
+            true,
+        );
+
+        if (len > 0) {
+            std.debug.print("{s}", .{buf[0..@intCast(len)]});
+        }
+    }
+
+    /// Print statistics
+    pub fn printStats(self: *const Self) void {
+        if (self.speculation_rounds == 0) return;
+
+        const acceptance_rate = if (self.draft_tokens_generated > 0)
+            @as(f64, @floatFromInt(self.accepted_tokens)) * 100.0 /
+                @as(f64, @floatFromInt(self.draft_tokens_generated))
+        else
+            0.0;
+
+        const tokens_per_round = @as(f64, @floatFromInt(self.total_tokens)) /
+            @as(f64, @floatFromInt(self.speculation_rounds));
+
+        std.debug.print("═══════════════════════════════════════════════════════════════\n", .{});
+        std.debug.print("                   SPECULATIVE DECODING STATS                  \n", .{});
+        std.debug.print("═══════════════════════════════════════════════════════════════\n", .{});
+        std.debug.print("Total tokens generated:    {}\n", .{self.total_tokens});
+        std.debug.print("Draft tokens proposed:     {}\n", .{self.draft_tokens_generated});
+        std.debug.print("Draft tokens accepted:     {}\n", .{self.accepted_tokens});
+        std.debug.print("Acceptance rate:           {d:.1}%\n", .{acceptance_rate});
+        std.debug.print("Speculation rounds:        {}\n", .{self.speculation_rounds});
+        std.debug.print("Tokens per round:          {d:.2}\n", .{tokens_per_round});
+        std.debug.print("═══════════════════════════════════════════════════════════════\n", .{});
+    }
+};
