+//! Token-Batch Loader for MoE Expert Weights
+//!
+//! Implements the "Firehose" pattern: SSD queue must NEVER be empty.
+//!
+//! Key Insight (from user):
+//!   - Current: "Stop-and-Go" - issue read, wait, issue next read
+//!   - Required: "Firehose" - 5-10 reads queued so SSD never relaxes
+//!
+//! With 98.5% hit rate, we predict the ENTIRE token (all 32 layers) upfront.
+//!
+//! Architecture:
+//!   - 4 staging buffers (4 × 192MB = 768MB)
+//!   - Request queue (32 slots, one per layer)
+//!   - IO thread races ahead, GPU follows
+//!   - Buffers recycled as GPU finishes each layer
+//!
+//! Expected: ~3.0 TPS (up from 0.47 TPS with single-layer prefetch)
+
+const std = @import("std");
+const objc = @import("inference/metal/objc.zig");
+
+const c = @cImport({
+    @cInclude("fcntl.h");
+    @cInclude("unistd.h");
+});
+
+pub const TokenBatchLoader = struct {
+    const Self = @This();
+
+    /// Number of staging buffers (pipelining depth)
+    pub const NUM_BUFFERS: usize = 4;
+    /// Maximum experts per layer - SHOTGUN PREFETCH: 4 candidates for higher hit rate
+    /// We prefetch Top-4 but only use Top-2 for compute - extra 2 are insurance
+    pub const MAX_EXPERTS: usize = 4;
+    /// Tensors per expert: gate, up, down
+    pub const TENSORS_PER_EXPERT: usize = 3;
+    /// Total slots per buffer = 4 experts × 3 tensors = 12
+    pub const SLOTS_PER_BUFFER: usize = MAX_EXPERTS * TENSORS_PER_EXPERT; // 12
+    /// Size of each tensor slot (~27MB for Mixtral Q4_K expert weights)
+    pub const SLOT_SIZE: usize = 32 * 1024 * 1024; // 32MB to be safe
+    /// Buffer size = 12 slots × 32MB = 384MB per buffer (4 buffers = 1.5GB total)
+    pub const BUFFER_SIZE: usize = SLOTS_PER_BUFFER * SLOT_SIZE;
+    /// Total number of layers
+    pub const NUM_LAYERS: usize = 32;
+
+    /// Expert tensor info for loading
+    pub const ExpertTensorInfo = struct {
+        gate_offset: usize,
+        gate_size: usize,
+        up_offset: usize,
+        up_size: usize,
+        down_offset: usize,
+        down_size: usize,
+    };
+
+    /// Result type for layer data
+    pub const LayerResult = struct {
+        buffer: objc.MTLBuffer,
+        gate_offsets: [MAX_EXPERTS]usize,
+        up_offsets: [MAX_EXPERTS]usize,
+        down_offsets: [MAX_EXPERTS]usize,
+        expert_count: usize,
+    };
+
+    /// Stats for performance tracking
+    pub const Stats = struct {
+        layers_loaded: u64,
+        bytes_loaded_mb: u64,
+        queue_depth_sum: u64,
+        queue_samples: u64,
+    };
+
+    /// Prediction input for a single layer (used by submitTokenBatch)
+    pub const LayerPrediction = struct {
+        expert_ids: [MAX_EXPERTS]u8,
+        expert_count: u8,
+        tensor_infos: [MAX_EXPERTS]ExpertTensorInfo,
+    };
+
+    /// Request for a single layer
+    const LayerRequest = struct {
+        layer_idx: u8,
+        expert_ids: [MAX_EXPERTS]u8,
+        expert_count: u8,
+        tensor_infos: [MAX_EXPERTS]ExpertTensorInfo,
+        valid: bool,
+    };
+
+    /// Staging buffer state
+    const StagingBuffer = struct {
+        memory: []align(4096) u8,
+        metal_buffer: objc.MTLBuffer,
+        /// Which layer is loaded (-1 = free)
+        layer_idx: i32,
+        /// Tensor offsets within buffer
+        tensor_offsets: [SLOTS_PER_BUFFER]usize,
+        tensor_sizes: [SLOTS_PER_BUFFER]usize,
+        expert_count: usize,
+    };
+
+    allocator: std.mem.Allocator,
+    device: objc.MTLDevice,
+
+    /// The 4 staging buffers
+    buffers: [NUM_BUFFERS]StagingBuffer,
+
+    /// File descriptor for pread
+    file_fd: c_int,
+    tensor_data_offset: usize,
+
+    /// Request queue (ring buffer for 32 layers)
+    request_queue: [NUM_LAYERS]LayerRequest,
+    queue_head: std.atomic.Value(u32), // Producer writes here
+    queue_tail: std.atomic.Value(u32), // Consumer reads here
+
+    /// Per-layer ready signals
+    layer_ready: [NUM_LAYERS]std.atomic.Value(bool),
+    /// Which buffer holds each layer (-1 = none)
+    layer_buffer: [NUM_LAYERS]std.atomic.Value(i8),
+
+    /// Buffer availability
+    buffer_free: [NUM_BUFFERS]std.atomic.Value(bool),
+
+    /// IO thread
+    io_thread: ?std.Thread,
+    io_running: std.atomic.Value(bool),
+    work_available: std.Thread.Semaphore,
+
+    /// Statistics
+    layers_loaded: std.atomic.Value(u64),
+    bytes_loaded: std.atomic.Value(u64),
+    queue_depth_sum: std.atomic.Value(u64),
+    queue_samples: std.atomic.Value(u64),
+
+    pub fn init(
+        allocator: std.mem.Allocator,
+        device: objc.MTLDevice,
+        file_path: []const u8,
+        tensor_data_offset: usize,
+    ) !*Self {
+        const self = try allocator.create(Self);
+        errdefer allocator.destroy(self);
+
+        // Open file for pread
+        const path_z = try allocator.dupeZ(u8, file_path);
+        defer allocator.free(path_z);
+
+        const fd = c.open(path_z.ptr, c.O_RDONLY);
+        if (fd < 0) return error.FileOpenFailed;
+        errdefer _ = c.close(fd);
+
+        // Initialize buffers
+        var buffers: [NUM_BUFFERS]StagingBuffer = undefined;
+        for (0..NUM_BUFFERS) |i| {
+            const mem = try allocator.alignedAlloc(u8, .fromByteUnits(4096), BUFFER_SIZE);
+            errdefer allocator.free(mem);
+
+            const metal_buf = objc.deviceNewBufferNoCopy(
+                device,
+                @ptrCast(mem.ptr),
+                BUFFER_SIZE,
+                objc.MTLResourceStorageModeShared,
+            ) orelse return error.MetalBufferCreationFailed;
+
+            buffers[i] = .{
+                .memory = mem,
+                .metal_buffer = metal_buf,
+                .layer_idx = -1,
+                .tensor_offsets = .{0} ** SLOTS_PER_BUFFER,
+                .tensor_sizes = .{0} ** SLOTS_PER_BUFFER,
+                .expert_count = 0,
+            };
+        }
+
+        // Initialize request queue
+        var request_queue: [NUM_LAYERS]LayerRequest = undefined;
+        for (0..NUM_LAYERS) |i| {
+            request_queue[i] = .{
+                .layer_idx = @intCast(i),
+                .expert_ids = .{ 0, 0, 0, 0 },
+                .expert_count = 0,
+                .tensor_infos = undefined,
+                .valid = false,
+            };
+        }
+
+        // Initialize per-layer state
+        var layer_ready: [NUM_LAYERS]std.atomic.Value(bool) = undefined;
+        var layer_buffer: [NUM_LAYERS]std.atomic.Value(i8) = undefined;
+        for (0..NUM_LAYERS) |i| {
+            layer_ready[i] = std.atomic.Value(bool).init(false);
+            layer_buffer[i] = std.atomic.Value(i8).init(-1);
+        }
+
+        // Initialize buffer availability
+        var buffer_free: [NUM_BUFFERS]std.atomic.Value(bool) = undefined;
+        for (0..NUM_BUFFERS) |i| {
+            buffer_free[i] = std.atomic.Value(bool).init(true);
+        }
+
+        self.* = Self{
+            .allocator = allocator,
+            .device = device,
+            .buffers = buffers,
+            .file_fd = fd,
+            .tensor_data_offset = tensor_data_offset,
+            .request_queue = request_queue,
+            .queue_head = std.atomic.Value(u32).init(0),
+            .queue_tail = std.atomic.Value(u32).init(0),
+            .layer_ready = layer_ready,
+            .layer_buffer = layer_buffer,
+            .buffer_free = buffer_free,
+            .io_thread = null,
+            .io_running = std.atomic.Value(bool).init(false),
+            .work_available = .{},
+            .layers_loaded = std.atomic.Value(u64).init(0),
+            .bytes_loaded = std.atomic.Value(u64).init(0),
+            .queue_depth_sum = std.atomic.Value(u64).init(0),
+            .queue_samples = std.atomic.Value(u64).init(0),
+        };
+
+        std.log.info("TokenBatchLoader: Allocated {} × {}MB staging buffers ({}MB total)", .{
+            NUM_BUFFERS,
+            BUFFER_SIZE / (1024 * 1024),
+            NUM_BUFFERS * BUFFER_SIZE / (1024 * 1024),
+        });
+
+        return self;
+    }
+
+    pub fn deinit(self: *Self) void {
+        self.stopIOThread();
+
+        if (self.file_fd >= 0) _ = c.close(self.file_fd);
+
+        for (0..NUM_BUFFERS) |i| {
+            objc.release(self.buffers[i].metal_buffer);
+            self.allocator.free(self.buffers[i].memory);
+        }
+
+        const stats = self.getStats();
+        std.log.info("TokenBatchLoader: {} layers, {}MB loaded, avg queue depth {d:.1}", .{
+            stats.layers_loaded,
+            stats.bytes_loaded_mb,
+            if (stats.queue_samples > 0)
+                @as(f64, @floatFromInt(stats.queue_depth_sum)) / @as(f64, @floatFromInt(stats.queue_samples))
+            else
+                0.0,
+        });
+
+        self.allocator.destroy(self);
+    }
+
+    pub fn startIOThread(self: *Self) !void {
+        if (self.io_thread != null) return;
+        self.io_running.store(true, .release);
+        self.io_thread = try std.Thread.spawn(.{}, ioWorker, .{self});
+        std.log.info("TokenBatchLoader: IO thread started (firehose mode)", .{});
+    }
+
+    pub fn stopIOThread(self: *Self) void {
+        if (self.io_thread == null) return;
+        self.io_running.store(false, .release);
+        self.work_available.post(); // Wake up if sleeping
+        if (self.io_thread) |t| {
+            t.join();
+            self.io_thread = null;
+        }
+    }
+
+    // =========================================================================
+    // Producer API (Main Thread)
+    // =========================================================================
+
+    /// Submit all 32 layer predictions for a token (call at token start)
+    pub fn submitTokenBatch(
+        self: *Self,
+        predictions: []const LayerPrediction,
+    ) void {
+        // Reset all layer states for new token
+        for (0..NUM_LAYERS) |i| {
+            self.layer_ready[i].store(false, .release);
+            self.layer_buffer[i].store(-1, .release);
+        }
+
+        // Mark all buffers as free
+        for (0..NUM_BUFFERS) |i| {
+            self.buffer_free[i].store(true, .release);
+        }
+
+        // Queue all layer requests
+        const count = @min(predictions.len, NUM_LAYERS);
+        for (0..count) |i| {
+            self.request_queue[i] = .{
+                .layer_idx = @intCast(i),
+                .expert_ids = predictions[i].expert_ids,
+                .expert_count = predictions[i].expert_count,
+                .tensor_infos = predictions[i].tensor_infos,
+                .valid = true,
+            };
+        }
+
+        // Update queue pointers
+        self.queue_tail.store(0, .release);
+        self.queue_head.store(@intCast(count), .release);
+
+        // Track queue depth
+        _ = self.queue_depth_sum.fetchAdd(count, .monotonic);
+        _ = self.queue_samples.fetchAdd(1, .monotonic);
+
+        // Wake IO thread
+        self.work_available.post();
+    }
+
+    /// Wait for a specific layer to be ready and get its data
+    pub fn waitForLayer(self: *Self, layer_idx: usize) ?LayerResult {
+        if (layer_idx >= NUM_LAYERS) return null;
+
+        // Spin-wait for layer to be ready (could use semaphore for efficiency)
+        while (!self.layer_ready[layer_idx].load(.acquire)) {
+            if (!self.io_running.load(.acquire)) return null;
+            std.Thread.yield() catch {};
+        }
+
+        const buf_idx = self.layer_buffer[layer_idx].load(.acquire);
+        if (buf_idx < 0 or buf_idx >= NUM_BUFFERS) return null;
+
+        const buffer = &self.buffers[@intCast(buf_idx)];
+        var result = LayerResult{
+            .buffer = buffer.metal_buffer,
+            .gate_offsets = .{0} ** MAX_EXPERTS,
+            .up_offsets = .{0} ** MAX_EXPERTS,
+            .down_offsets = .{0} ** MAX_EXPERTS,
+            .expert_count = buffer.expert_count,
+        };
+
+        for (0..buffer.expert_count) |ei| {
+            const base = ei * TENSORS_PER_EXPERT;
+            result.gate_offsets[ei] = buffer.tensor_offsets[base + 0];
+            result.up_offsets[ei] = buffer.tensor_offsets[base + 1];
+            result.down_offsets[ei] = buffer.tensor_offsets[base + 2];
+        }
+
+        return result;
+    }
+
+    /// Release a layer's buffer so IO thread can reuse it
+    pub fn releaseLayer(self: *Self, layer_idx: usize) void {
+        if (layer_idx >= NUM_LAYERS) return;
+
+        const buf_idx = self.layer_buffer[layer_idx].load(.acquire);
+        if (buf_idx >= 0 and buf_idx < NUM_BUFFERS) {
+            self.buffer_free[@intCast(buf_idx)].store(true, .release);
+            self.layer_buffer[layer_idx].store(-1, .release);
+        }
+
+        // Wake IO thread in case it's waiting for a buffer
+        self.work_available.post();
+    }
+
+    // =========================================================================
+    // Consumer (IO Thread) - Firehose Loop
+    // =========================================================================
+
+    fn ioWorker(self: *Self) void {
+        std.log.debug("TokenBatchLoader: IO worker starting (firehose mode)", .{});
+
+        while (self.io_running.load(.acquire)) {
+            // Get next request from queue
+            const tail = self.queue_tail.load(.acquire);
+            const head = self.queue_head.load(.acquire);
+
+            if (tail >= head) {
+                // Queue empty, wait for work
+                self.work_available.wait();
+                continue;
+            }
+
+            const req = self.request_queue[tail % NUM_LAYERS];
+            if (!req.valid) {
+                _ = self.queue_tail.fetchAdd(1, .release);
+                continue;
+            }
+
+            // CACHE-FIRST: Skip layers with no experts to load (already cached!)
+            if (req.expert_count == 0) {
+                // Mark layer ready immediately (no IO needed)
+                self.layer_ready[req.layer_idx].store(true, .release);
+                _ = self.queue_tail.fetchAdd(1, .release);
+                continue;
+            }
+
+            // Find a free buffer (spin-wait if necessary)
+            var buf_idx: ?usize = null;
+            while (buf_idx == null and self.io_running.load(.acquire)) {
+                for (0..NUM_BUFFERS) |i| {
+                    if (self.buffer_free[i].load(.acquire)) {
+                        // Try to claim it
+                        if (self.buffer_free[i].cmpxchgStrong(true, false, .acq_rel, .acquire) == null) {
+                            buf_idx = i;
+                            break;
+                        }
+                    }
+                }
+                if (buf_idx == null) {
+                    // All buffers busy, yield and retry
+                    std.Thread.yield() catch {};
+                }
+            }
+
+            if (buf_idx == null) continue; // Shutting down
+
+            // Load layer data into buffer
+            const buffer = &self.buffers[buf_idx.?];
+            var slot_idx: usize = 0;
+            var total_bytes: usize = 0;
+
+            for (0..req.expert_count) |ei| {
+                const info = req.tensor_infos[ei];
+
+                // Gate
+                const gate_offset = slot_idx * SLOT_SIZE;
+                total_bytes += self.preadInto(buffer.memory, gate_offset, info.gate_offset, info.gate_size);
+                buffer.tensor_offsets[slot_idx] = gate_offset;
+                slot_idx += 1;
+
+                // Up
+                const up_offset = slot_idx * SLOT_SIZE;
+                total_bytes += self.preadInto(buffer.memory, up_offset, info.up_offset, info.up_size);
+                buffer.tensor_offsets[slot_idx] = up_offset;
+                slot_idx += 1;
+
+                // Down
+                const down_offset = slot_idx * SLOT_SIZE;
+                total_bytes += self.preadInto(buffer.memory, down_offset, info.down_offset, info.down_size);
+                buffer.tensor_offsets[slot_idx] = down_offset;
+                slot_idx += 1;
+            }
+
+            buffer.layer_idx = req.layer_idx;
+            buffer.expert_count = req.expert_count;
+
+            // Update stats
+            _ = self.layers_loaded.fetchAdd(1, .monotonic);
+            _ = self.bytes_loaded.fetchAdd(total_bytes, .monotonic);
+
+            // Mark layer as ready
+            self.layer_buffer[req.layer_idx].store(@intCast(buf_idx.?), .release);
+            self.layer_ready[req.layer_idx].store(true, .release);
+
+            // Advance queue
+            _ = self.queue_tail.fetchAdd(1, .release);
+        }
+
+        std.log.debug("TokenBatchLoader: IO worker exiting", .{});
+    }
+
+    fn preadInto(self: *Self, memory: []u8, dest_offset: usize, file_offset: usize, size: usize) usize {
+        const dest_ptr = memory.ptr + dest_offset;
+        const bytes_read = c.pread(
+            self.file_fd,
+            dest_ptr,
+            size,
+            @intCast(self.tensor_data_offset + file_offset),
+        );
+        return if (bytes_read > 0) @intCast(bytes_read) else 0;
+    }
+
+    pub fn getStats(self: *Self) Stats {
+        return Stats{
+            .layers_loaded = self.layers_loaded.load(.monotonic),
+            .bytes_loaded_mb = self.bytes_loaded.load(.monotonic) / (1024 * 1024),
+            .queue_depth_sum = self.queue_depth_sum.load(.monotonic),
+            .queue_samples = self.queue_samples.load(.monotonic),
+        };
+    }
+
+    // =========================================================================
+    // Sync Loading API (for fallback on prediction miss)
+    // =========================================================================
+
+    /// Synchronously load expert data into a buffer (for fallback path)
+    /// Uses buffer 0 directly - caller must ensure this is not in use
+    pub fn loadExpertsSync(
+        self: *Self,
+        expert_infos: []const ExpertTensorInfo,
+    ) ?LayerResult {
+        if (expert_infos.len == 0 or expert_infos.len > MAX_EXPERTS) return null;
+
+        // Use buffer 0 for sync loading (claim it)
+        while (self.buffer_free[0].cmpxchgStrong(true, false, .acq_rel, .acquire) != null) {
+            std.Thread.yield() catch {};
+        }
+
+        const buffer = &self.buffers[0];
+        var slot_idx: usize = 0;
+        var total_bytes: usize = 0;
+
+        for (0..expert_infos.len) |ei| {
+            const info = expert_infos[ei];
+
+            // Gate
+            const gate_offset = slot_idx * SLOT_SIZE;
+            total_bytes += self.preadInto(buffer.memory, gate_offset, info.gate_offset, info.gate_size);
+            buffer.tensor_offsets[slot_idx] = gate_offset;
+            slot_idx += 1;
+
+            // Up
+            const up_offset = slot_idx * SLOT_SIZE;
+            total_bytes += self.preadInto(buffer.memory, up_offset, info.up_offset, info.up_size);
+            buffer.tensor_offsets[slot_idx] = up_offset;
+            slot_idx += 1;
+
+            // Down
+            const down_offset = slot_idx * SLOT_SIZE;
+            total_bytes += self.preadInto(buffer.memory, down_offset, info.down_offset, info.down_size);
+            buffer.tensor_offsets[slot_idx] = down_offset;
+            slot_idx += 1;
+        }
+
+        buffer.expert_count = expert_infos.len;
+
+        // Update stats
+        _ = self.bytes_loaded.fetchAdd(total_bytes, .monotonic);
+
+        var result = LayerResult{
+            .buffer = buffer.metal_buffer,
+            .gate_offsets = .{0} ** MAX_EXPERTS,
+            .up_offsets = .{0} ** MAX_EXPERTS,
+            .down_offsets = .{0} ** MAX_EXPERTS,
+            .expert_count = expert_infos.len,
+        };
+
+        for (0..expert_infos.len) |ei| {
+            const base = ei * TENSORS_PER_EXPERT;
+            result.gate_offsets[ei] = buffer.tensor_offsets[base + 0];
+            result.up_offsets[ei] = buffer.tensor_offsets[base + 1];
+            result.down_offsets[ei] = buffer.tensor_offsets[base + 2];
+        }
+
+        return result;
+    }
+
+    /// Release the sync loading buffer
+    pub fn releaseSyncBuffer(self: *Self) void {
+        self.buffer_free[0].store(true, .release);
+    }
+};
